mapper.insert:
INSERT INTO t_page_view_stat (id, page_type, page_key, day, cnt)
VALUES (#{id}, #{pageType}, #{pageKey}, #{day}, #{delta})
ON DUPLICATE KEY UPDATE cnt = cnt + #{delta}

mapper.select:
SELECT page_type AS pageType, page_key AS pageKey, SUM(cnt) AS cnt FROM t_page_view_stat WHERE day >= #{startDay}
AND page_type = #{pageType}
GROUP BY page_type, page_key ORDER BY cnt DESC
